import { DICTIONARY_TERMS } from "../engine/dictionary/index.ts";
import type { DictionaryTerm } from "../engine/dictionary/types.ts";

export type Category = "Foundations" | "Story & screen" | "Advertising" | "Business & startups" | "Rooms & slides" | "Evidence & claims" | "Rights, labour & process" | "Access & inclusion";
export interface PitchTerm extends DictionaryTerm { category: Category; }
interface Seed { id: string; label: string; aliases?: string[]; plain: string; why: string; changes: string; category: Category; }
const s = (value: Seed): PitchTerm => ({ id: value.id, label: value.label, aliases: value.aliases ?? [], plain: value.plain, whyItMatters: value.why, changes: value.changes, oftenConfusedWith: [], related: [], lenses: {}, category: value.category });

const US_SPELLING: Readonly<Record<string, string>> = {
  artefact: "artifact", artefacts: "artifacts", behaviour: "behavior", behaviours: "behaviors",
  capitalisation: "capitalization", catalogue: "catalog", catalogues: "catalogs", centre: "center", centred: "centered",
  colour: "color", colours: "colors", fulfil: "fulfill", fulfils: "fulfills", instalment: "installment", instalments: "installments",
  judgement: "judgment", labour: "labor", licence: "license", licences: "licenses", localisation: "localization",
  modelling: "modeling", neighbour: "neighbor", neighbouring: "neighboring", neighbours: "neighbors",
  organisation: "organization", organisations: "organizations", organise: "organize", organised: "organized",
  organises: "organizes", organising: "organizing", prioritise: "prioritize", prioritised: "prioritized",
  prioritises: "prioritizes", prioritising: "prioritizing", programme: "program", programmes: "programs",
  recognise: "recognize", recognised: "recognized", recognises: "recognizes", recognising: "recognizing", travelling: "traveling",
};

export function usEnglish(value: string): string {
  return value.replace(/\b(artefacts?|behaviou?rs?|capitalisation|catalogues?|centred?|colours?|fulfils?|instalments?|judgement|labour|licences?|localisation|modelling|neighbours?|neighbouring|organisations?|organis(?:e|ed|es|ing)|prioritis(?:e|ed|es|ing)|programmes?|recognis(?:e|ed|es|ing)|travelling)\b/gi, (word) => {
    const replacement = US_SPELLING[word.toLowerCase()] ?? word;
    return /^[A-Z]/.test(word) ? replacement[0]!.toUpperCase() + replacement.slice(1) : replacement;
  });
}

function forDisplay(term: PitchTerm): PitchTerm {
  return {
    ...term,
    label: usEnglish(term.label),
    aliases: [...new Set([...term.aliases, ...term.aliases.map(usEnglish)])],
    plain: usEnglish(term.plain),
    whyItMatters: usEnglish(term.whyItMatters),
    changes: usEnglish(term.changes),
  };
}

