const storyIds = new Set(["logline","tagline","synopsis","series-engine","limited-series","season-arc","episode-examples","episode-list","pilot","pitch-bible","production-bible","lookbook","treatment","directors-treatment","theme","visual-reference"]);
const rightsIds = new Set(["attachment","image-provenance","specialist-first","speculative-work","paid-help","portfolio-work","current-requirement","source-freshness","requirement-state"]);
const slideIds = new Set(["page-job","section-job","reader-question","copy-band","preview-fit","smallest-view","type-pressure","channel-competition","split-source","mechanical-split","delivery-mode","live-deck","leave-behind","dual-use","appendix","reference-slide"]);
const evidenceIds = new Set(["market-proof","result-footing","confidence","score","convention"]);
function categoryFor(term: DictionaryTerm): Category {
  if (storyIds.has(term.id)) return "Story & screen";
  if (rightsIds.has(term.id)) return "Rights, labour & process";
  if (slideIds.has(term.id)) return "Rooms & slides";
  if (evidenceIds.has(term.id)) return "Evidence & claims";
  return "Foundations";
}

export const TERMS: readonly PitchTerm[] = [
  ...DICTIONARY_TERMS.map((term) => ({ ...term, category: categoryFor(term) })),
  ...EXTRA,
].map(forDisplay).sort((a, b) => a.label.localeCompare(b.label));

export const CATEGORIES: readonly Category[] = ["Foundations","Story & screen","Advertising","Business & startups","Rooms & slides","Evidence & claims","Rights, labour & process","Access & inclusion"];
